// In src/commands/index.rs
use crate::output::{Output, progress::ProgressIndicator};

pub fn run_index(args: IndexArgs, output: &Output) -> Result<()> {
    let docs = load_documents(&args.archive_path)?;
    let total = docs.len() as u64;

    output.print_verbose(&format!("Found {} documents to index", total));

    let mut progress = ProgressIndicator::new_bar(total, "Indexing documents", output);

    for (i, doc) in docs.iter().enumerate() {
        index_document(doc)?;
        progress.update((i + 1) as u64);

        // Verbose: Log every 1000 docs
        if output.is_verbose() && (i + 1) % 1000 == 0 {
            output.print_verbose(&format!("Indexed {} documents...", i + 1));
        }
    }

    progress.finish(&format!("Indexed {} documents", total));
    Ok(())
}
