// In src/commands/repl.rs
use crate::output::{Output, repl::{ReplPrompt, ReplHistory, render_repl_help, clear_screen, SearchMode}};

pub fn run_repl(output: &Output) -> Result<()> {
    let mut state = ReplState::new();
    let prompt = ReplPrompt::new(&output.theme);

    // Show status line
    let status = ReplStatusLine::new(
        state.archive_path.clone(),
        state.doc_count,
        state.index_status,
        &output.theme,
    );
    output.print(&status.render(output));

    loop {
        // Render prompt
        print!("{}", prompt.render(output, state.mode));
        std::io::stdout().flush()?;

        let line = read_line()?;

        match parse_command(&line) {
            ReplCommand::Search(query) => {
                let start = Instant::now();
                let results = search(&query, &state)?;
                let timing = start.elapsed();

                render_search_results(output, &results, &query, timing);
                state.add_to_history(&query, results.len(), timing);
            }
            ReplCommand::Mode(mode) => {
                state.mode = mode;
                output.print_normal(&format!("Switched to {} mode", mode));
            }
            ReplCommand::Help => {
                render_repl_help(output);
            }
            ReplCommand::History => {
                ReplHistory::new(&state.history, &output.theme).render(output);
            }
            ReplCommand::Clear => {
                clear_screen(output);
            }
            ReplCommand::Quit => break,
            ReplCommand::Unknown(cmd) => {
                output.print(&format!("Unknown command: {}", cmd));
            }
        }
    }

    Ok(())
}
